/**
 * CLI: read verification bundle JSON from stdin or file, exit 0 iff verify passes.
 * Usage: pnpm exec tsx ./scripts/verify-bundle.ts [path/to/bundle.json]
 */
import * as fs from 'node:fs';
import { verifyBundle } from '../src/verify-bundle';

function main(): void {
  const path = process.argv[2];
  const raw =
    path === undefined || path === '-'
      ? fs.readFileSync(0, 'utf8')
      : fs.readFileSync(path, 'utf8');
  let json: unknown;
  try {
    json = JSON.parse(raw) as unknown;
  } catch {
    process.stderr.write('verify-bundle: invalid JSON\n');
    process.exit(1);
  }
  const r = verifyBundle(json);
  if (!r.ok) {
    process.stderr.write(`verify-bundle: ${r.reason}\n`);
    process.exit(1);
  }
  process.stdout.write('verify-bundle: ok\n');
  process.exit(0);
}

main();
